1	import { runScenario, KNOWN_ITEM_TYPES } from "./claim-office.js";
2	
3	type Item = { type: string };
4	type Damage = { itemType: string; amount: number };
5	type Incident = { damages: Damage[] };
6	type Step = { op: string; items?: Item[]; policy?: number; incident?: Incident };
7	type Scenario = { steps: Step[] };
8	
9	const readStdin = async (): Promise<string> => {
10	  const chunks: Buffer[] = [];
11	  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
12	  return Buffer.concat(chunks).toString("utf8");
13	};
14	
15	const quotedItems = (scenario: Scenario): Item[] =>
16	  scenario.steps.filter((step) => step.op === "quote").flatMap((step) => step.items ?? []);
17	
18	const findUnknownItemType = (scenario: Scenario): string | undefined =>
19	  quotedItems(scenario).find((item) => !KNOWN_ITEM_TYPES.has(item.type))?.type;
20	
21	const fail = (message: string): never => {
22	  process.stderr.write(`${message}\n`);
23	  process.exit(1);
24	};
25	
26	const policyItemsFor = (scenario: Scenario, step: Step): Item[] =>
27	  step.policy !== undefined ? scenario.steps[step.policy]?.items ?? [] : [];
28	
29	const uninsuredDamagesIn = (scenario: Scenario, step: Step): Damage[] => {
30	  const policyItems = policyItemsFor(scenario, step);
31	  return (step.incident?.damages ?? []).filter(
32	    (damage) => !policyItems.some((item) => item.type === damage.itemType),
33	  );
34	};
35	
36	const findUninsuredDamage = (scenario: Scenario): Damage | undefined =>
37	  scenario.steps
38	    .filter((step) => step.op === "claim")
39	    .flatMap((step) => uninsuredDamagesIn(scenario, step))[0];
40	
41	const findNegativeDamage = (scenario: Scenario): Damage | undefined =>
42	  scenario.steps
43	    .filter((step) => step.op === "claim")
44	    .flatMap((step) => step.incident?.damages ?? [])
45	    .find((damage) => damage.amount < 0);
46	
47	const main = async (): Promise<void> => {
48	  const scenario = JSON.parse(await readStdin());
49	
50	  const unknownType = findUnknownItemType(scenario);
51	  if (unknownType !== undefined) fail(`Unknown item type: ${unknownType}`);
52	
53	  const uninsured = findUninsuredDamage(scenario);
54	  if (uninsured) fail(`Damage references item not in policy: ${uninsured.itemType}`);
55	
56	  const negative = findNegativeDamage(scenario);
57	  if (negative) fail(`Damage amount must be non-negative: ${negative.amount}`);
58	
59	  process.stdout.write(JSON.stringify(runScenario(scenario)) + "\n");
60	};
61	
62	main().catch((err: Error) => fail(`Error: ${err.message}`));
63

1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_RATE = 0.15;
9	const COMPONENT_BASE = 25;
10	const COMPONENT_BLOCK_BASE = 60;
11	const BLOCK_SIZE = 3;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
15	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	export const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
20	
21	const BASE_PREMIUM: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	};
27	
28	const INSURANCE_VALUE: Record<string, number> = {
29	  sword: 1000,
30	  amulet: 600,
31	  staff: 800,
32	  potion: 400,
33	  rune: 250,
34	  moonstone: 250,
35	};
36	
37	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
38	type Customer = { yearsWithMHPCO: number };
39	type Damage = { itemType: string; amount: number };
40	type Incident = { cause: string; damages: Damage[] };
41	type QuoteStep = { op: "quote"; items: Item[] };
42	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
43	type Step = QuoteStep | ClaimStep;
44	type Scenario = { customer: Customer; steps: Step[] };
45	
46	type QuoteResult = { premium: number };
47	type ClaimResult = { payout: number; remainingCap: number };
48	type Result = QuoteResult | ClaimResult;
49	
50	type Policy = { items: Item[]; cap: number; remainingCap: number };
51	
52	const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);
53	
54	const baseForCount = (count: number): number =>
55	  count === BLOCK_SIZE ? COMPONENT_BLOCK_BASE : count * COMPONENT_BASE;
56	
57	const countByType = (items: Item[]): Record<string, number> => {
58	  const counts: Record<string, number> = {};
59	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
60	  return counts;
61	};
62	
63	const componentBase = (items: Item[]): number =>
64	  Object.values(countByType(items)).reduce((sum, count) => sum + baseForCount(count), 0);
65	
66	const itemBase = (item: Item): number => BASE_PREMIUM[item.type];
67	
68	const itemSurcharge = (item: Item): number => {
69	  const base = itemBase(item);
70	  const curseSurcharge = item.cursed ? base * CURSE_RATE : 0;
71	  const enchantmentSurcharge =
72	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
73	  return curseSurcharge + enchantmentSurcharge;
74	};
75	
76	const quotePremium = (items: Item[], customer: Customer, contractIndex: number): number => {
77	  const components = items.filter(isComponent);
78	  const mains = items.filter((i) => !isComponent(i));
79	  const policyBase = mains.reduce((sum, item) => sum + itemBase(item), 0) + componentBase(components);
80	  const itemSurcharges = mains.reduce((sum, item) => sum + itemSurcharge(item), 0);
81	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
82	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
83	  const followUp = contractIndex > 0 ? policyBase * FOLLOWUP_RATE : 0;
84	  return Math.ceil(policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
85	};
86	
87	const policyInsuranceSum = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
89	
90	const damagePayout = (damage: Damage, item: Item | undefined): number => {
91	  const enchantment = item?.enchantment ?? 0;
92	  const reimbursableFraction = enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
93	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
94	    : 1;
95	  return Math.max(0, damage.amount * reimbursableFraction - DEDUCTIBLE);
96	};
97	
98	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
99	  const grossPayout = incident.damages.reduce((sum, d) => {
100	    const item = policy.items.find((i) => i.type === d.itemType);
101	    return sum + damagePayout(d, item);
102	  }, 0);
103	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
104	  policy.remainingCap -= payout;
105	  return { payout, remainingCap: policy.remainingCap };
106	};
107	
108	export const runScenario = (scenario: Scenario): { results: Result[] } => {
109	  const policies: Record<number, Policy> = {};
110	  const results: Result[] = scenario.steps.map((step, index) => {
111	    if (step.op === "quote") {
112	      const cap = policyInsuranceSum(step.items) * CAP_MULTIPLIER;
113	      policies[index] = { items: step.items, cap, remainingCap: cap };
114	      return { premium: quotePremium(step.items, scenario.customer, index) };
115	    }
116	    return processClaim(policies[step.policy], step.incident);
117	  });
118	  return { results };
119	};
